export const checkId = 'start-script';
export const name = 'Start Script Present';
export const appliesTo = ['all'];

const APP_RUNTIMES = ['next', 'nuxt', 'astro', 'express', 'fastify', 'koa', 'hono', 'nitro', 'serve', 'http-server'];

function hasAppRuntimeDeps(pkg) {
  const deps = pkg.dependencies || {};
  return APP_RUNTIMES.some(d => d in deps);
}

function isPlaceholderScript(script) {
  return typeof script !== 'string' || script.trim().length <= 3 || script.toLowerCase().includes('todo');
}

function isLibraryOrTool(pkg) {
  if (!pkg) return false;

  if (pkg.bin && !hasAppRuntimeDeps(pkg)) return true;

  if (pkg.peerDependencies && Object.keys(pkg.peerDependencies).length > 0) {
    if (!hasAppRuntimeDeps(pkg)) return true;
  }

  const name = String(pkg.name || '').toLowerCase();
  const keywords = (pkg.keywords || []).map(k => String(k).toLowerCase());

  if (name.startsWith('@types/')) return true;
  if (/^(eslint|babel-plugin|rollup-plugin|vite-plugin|webpack-plugin|jest-|vitest-plugin|drizzle-|prisma|tslint-plugin)/.test(name)) return true;
  if (/(plugin|loader|preset|middleware|adapter)$/.test(name)) return true;

  const libraryKeywords = /\b(library|plugin|tool|cli|compiler|transpiler|bundler|formatter|linter|middleware|module|package|preset|loader|util|utility)\b/;
  if (keywords.some(k => libraryKeywords.test(k))) {
    const appKeywords = /\b(app|application|website|webapp|cms|blog|starter|template|dashboard|platform|deploy)\b/;
    if (!keywords.some(k => appKeywords.test(k)) && !hasAppRuntimeDeps(pkg)) return true;
  }

  const hasMain = !!pkg.main;
  const looksPublished = hasMain && !!(pkg.types || pkg.typings || pkg.publishConfig || (pkg.files && pkg.files.length > 0));
  if (looksPublished && !pkg.scripts?.start && !hasAppRuntimeDeps(pkg)) {
    if (keywords.some(k => /\b(framework|sdk|api-client|client)\b/.test(k))) {
      const serverFrameworkKw = keywords.some(k => /\b(server|http|rest|router|middleware)\b/.test(k));
      const appKw = keywords.some(k => /\b(app|application|website|cms|starter|template|deploy)\b/.test(k));
      if (serverFrameworkKw && !appKw && !hasAppRuntimeDeps(pkg)) return true;
    }
    return true;
  }

  return false;
}

function isMonorepo(pkg, tree) {
  if (!pkg && !tree) return false;
  if (pkg?.workspaces) return true;
  if (tree?.some(p => p === 'pnpm-workspace.yaml')) return true;
  const devDeps = pkg?.devDependencies || {};
  const deps = pkg?.dependencies || {};
  const monoTools = ['turbo', 'lerna', 'nx', '@nrwl/workspace', '@nx/workspace'];
  if (monoTools.some(t => t in devDeps || t in deps)) return true;
  if (tree?.some(p => p === 'packages/' || p.startsWith('packages/') || p === 'apps/' || p.startsWith('apps/'))) return true;
  return false;
}

async function hasDockerfileEntrypoint(tree, files) {
  if (!tree || !files) return false;
  const dockerfile = tree.find(p => p === 'Dockerfile' || p.endsWith('/Dockerfile'));
  if (!dockerfile) return false;
  try {
    const content = await files.get(dockerfile);
    return !!(content && /^\s*(CMD|ENTRYPOINT)\s/im.test(content));
  } catch (e) {
    console.error('Error reading Dockerfile:', e);
    return false;
  }
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  let pkg = packageJson;
  if (!pkg && files && typeof files.get === 'function') {
    try {
      const raw = await files.get('package.json');
      if (raw) pkg = JSON.parse(raw);
    } catch (e) {
      console.error('Error reading package.json via files.get:', e);
    }
  }

  try {
    if (repoType === 'empty' || !tree || tree.length === 0) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Empty repo — no start script needed',
        findings: [],
      };
    }

    if (!pkg) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No package.json found — start script check not applicable',
        findings: [],
      };
    }

    const scripts = pkg.scripts || {};
    const startKeys = ['start', 'serve', 'start:prod'];
    let activeScript = null;

    for (const key of startKeys) {
      if (key in scripts) {
        activeScript = scripts[key];
        break;
      }
    }

    if (activeScript !== null) {
      if (!isPlaceholderScript(activeScript)) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Start script found: "${activeScript}"`,
          findings: [],
        };
      }
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: `Start script may be placeholder: "${activeScript}"`,
        findings: [{ file: 'package.json', issue: 'Start script appears to be a placeholder' }],
      };
    }

    if (isLibraryOrTool(pkg)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library or tool package — start script not required',
        findings: [],
      };
    }

    if ((repoType === 'library' || repoType === 'tool' || repoType === 'framework') && !hasAppRuntimeDeps(pkg)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: `${repoType === 'library' ? 'Library' : repoType === 'tool' ? 'Tool' : 'Framework'} — start script not required`,
        findings: [],
      };
    }

    const monorepo = isMonorepo(pkg, tree);

    if (monorepo) {
      const devScript = scripts.dev;
      if ('dev' in scripts && typeof devScript === 'string' && !isPlaceholderScript(devScript)) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Monorepo start script found: "${devScript}"`,
          findings: [],
        };
      }

      let foundSubStart = false;
      let reads = 0;
      const maxReads = 8;
      let libCount = 0;
      let otherCount = 0;

      const searchDirs = ['apps/', 'services/', 'packages/'];

      for (const dir of searchDirs) {
        const subPkgs = tree.filter(p => {
          if (!p.startsWith(dir) || !p.endsWith('/package.json')) return false;
          const rest = p.slice(dir.length);
          return rest.split('/').length === 2;
        });

        for (const subPath of subPkgs) {
          if (reads >= maxReads) break;
          reads++;
          try {
            const content = await files.get(subPath);
            if (!content) continue;
            const sub = JSON.parse(content);
            const subScripts = sub.scripts || {};
            const subStart = subScripts.start || subScripts.serve || subScripts['start:prod'] || subScripts.dev;
            if (typeof subStart === 'string' && !isPlaceholderScript(subStart)) {
              foundSubStart = true;
              break;
            }
            if (isLibraryOrTool(sub)) {
              libCount++;
            } else {
              otherCount++;
            }
          } catch (e) {
            console.error(`Error reading ${subPath}:`, e);
          }
        }
        if (foundSubStart) break;
      }

      if (foundSubStart) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: 'Monorepo — start script found in sub-package',
          findings: [],
        };
      }

      if (libCount > 0 && otherCount === 0) {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'Library or tool monorepo — start script not required at root',
          findings: [],
        };
      }

      if (otherCount > 0) {
        return {
          checkId,
          status: 'fail',
          confidence: 'high',
          message: 'App monorepo — no start script found in root or app sub-packages',
          findings: [{ file: 'package.json', issue: 'Missing start script in app monorepo' }],
        };
      }

      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'Monorepo — no root start script found (may be in a sub-package)',
        findings: [{ file: 'package.json', issue: 'No root start script — verify individual packages/' }],
      };
    }

    if (tree.includes('Procfile')) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: 'Procfile found — deployment entrypoint present',
        findings: [],
      };
    }

    if (await hasDockerfileEntrypoint(tree, files)) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: 'Dockerfile with CMD/ENTRYPOINT found — deployment entrypoint present',
        findings: [],
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: 'No start script found in package.json',
      findings: [{ file: 'package.json', issue: 'Missing "start" script — required for deployment' }],
    };
  } catch (err) {
    console.error('start-script specialist error:', err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during check: ${err.message}`,
      findings: [],
    };
  }
}
